#include <vector>
#include <string>
#include <regex>
#include <map>
#include <algorithm>

using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    vector<pair<string, string>> valid;
    map<string, int> business_order = {
        {"electronics", 0},
        {"grocery", 1},
        {"pharmacy", 2},
        {"restaurant", 3}
    };

    for (int i = 0; i < code.size(); ++i) {
        if (code[i].empty()) continue;
        if (!regex_match(code[i], regex("^[a-zA-Z0-9_]+$"))) continue;
        string bl = businessLine[i];
        if (bl != "electronics" && bl != "grocery" && bl != "pharmacy" && bl != "restaurant") continue;
        if (!isActive[i]) continue;
        valid.push_back({bl, code[i]});
    }

    sort(valid.begin(), valid.end(), [&](const pair<string, string>& a, const pair<string, string>& b) {
